<?php
/**
 * Footer About Component
 *
 * @package ERDU_Lighting
 */

if (!defined('ABSPATH')) {
    exit;
}

class Erdu_Footer_About {
    public static function render($settings, $theme_settings) {
        if (!$settings['about'] && !$settings['social_show']) {
            return;
        }

        $social_svgs = self::get_social_svgs();
        ?>
        <div>
            <!-- Logo -->
            <div class="flex items-center gap-2 mb-4">
                <?php
                $logo_size = isset($settings['logo_size']) ? absint($settings['logo_size']) : 64;
                $logo_class = $logo_size <= 32 ? 'h-8' : '';
                ?>
                <?php if ($settings['logo_type'] === 'image' && $settings['logo_image']) : ?>
                    <img src="<?php echo esc_url($settings['logo_image']); ?>" alt="<?php echo esc_attr($settings['logo_text']); ?>" style="width: <?php echo esc_attr($logo_size); ?>px; height: auto;" class="shrink-0">
                <?php else : ?>
                    <?php if ($settings['logo_icon']) : ?>
                    <div class="rounded flex items-center justify-center shrink-0 erdu-bg-primary" style="width: <?php echo esc_attr($logo_size); ?>px; height: <?php echo esc_attr($logo_size); ?>px;">
                        <span class="text-white font-bold" style="font-size: <?php echo esc_attr(max(10, $logo_size * 0.4)); ?>px;"><?php echo esc_html($settings['logo_icon_t']); ?></span>
                    </div>
                    <?php endif; ?>
                    <span class="text-xl font-bold" style="color: <?php echo esc_attr($settings['heading_color']); ?>;"><?php echo esc_html($settings['logo_text']); ?></span>
                <?php endif; ?>
            </div>

            <!-- About Text -->
            <?php if ($settings['about']) : ?>
            <p class="text-sm mb-4" style="color: <?php echo esc_attr($settings['text_color']); ?>;"><?php echo esc_html($settings['about']); ?></p>
            <?php endif; ?>

            <!-- Social Links -->
            <?php 
            if ($settings['social_show']) : 
                $global_settings = get_option('erdu_settings', erdu_default_settings());
                $platforms = array('facebook', 'linkedin', 'youtube', 'instagram', 'twitter', 'whatsapp', 'wechat', 'tiktok');
                $has_links = false;
                foreach ($platforms as $platform) {
                    if (!empty($global_settings[$platform])) {
                        $has_links = true;
                        break;
                    }
                }
                
                if ($has_links) :
            ?>
            <div class="flex gap-3">
                <?php foreach ($platforms as $platform) :
                    $url = $global_settings[$platform] ?? '';
                    if (empty($url)) continue;
                    $label = ucfirst($platform);
                    $svg = $social_svgs[$platform] ?? $social_svgs['custom'];
                ?>
                <a href="<?php echo esc_url($url); ?>" target="_blank" rel="noopener"
                   class="w-8 h-8 rounded-full flex items-center justify-center transition-colors"
                   style="background-color: rgba(255,255,255,0.1); color: <?php echo esc_attr($settings['text_color']); ?>;"
                   onmouseover="this.style.backgroundColor='var(--erdu-primary, #F37021)'; this.style.color='#fff';"
                   onmouseout="this.style.backgroundColor='rgba(255,255,255,0.1)'; this.style.color='<?php echo esc_attr($settings['text_color']); ?>';"
                   aria-label="<?php echo esc_attr($label); ?>">
                    <svg class="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><?php echo wp_kses_post($svg); ?></svg>
                </a>
                <?php endforeach; ?>
            </div>
            <?php 
                endif; 
            endif; 
            ?>
        </div>
        <?php
    }

